      tags: Array.isArray(asset.tags) ? asset.tags : [],
      disciplineTags: Array.isArray(asset.disciplineTags) ? asset.disciplineTags : ['arch'],
      thumbnailKind: asset.thumbnailKind ?? 'schematic_plan',
