        roomBounded: loggia.roomBounded === true,
      });
    }
    if (Array.isArray(loggia.railingPathMm) && loggia.railingPathMm.length >= 2) {
      commands.push({
        type: 'createRailing',
        id: `${id}-railing`,
        name: loggia.railingName ?? `${id} railing`,
        pathMm: loggia.railingPathMm.map((point, index) =>
