    commands.push(...wallCommandsForVolume(wrapper, footprint));
    if (wrapper.createRoof === true) {
      commands.push({
        type: 'createRoof',
        id: `${id}-roof`,
        name: wrapper.roofName ?? `${id} roof`,
        referenceLevelId: assertString(
          wrapper.referenceLevelId ?? wrapper.levelId,
